```csharp
using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 25m, Quantity = 1 },
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45m, order.Total);
        Assert.HasCount(2, order.Items);
        Assert.IsNotNull(order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10m, Quantity = 1 },
        };

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5m, Quantity = 3 },
        };
        var created = _service.CreateOrder("cust-1", items);

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithMultipleOrders_ReturnsAllMatching()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10m, Quantity = 1 },
        };
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-B", items);

        // Act
        var orders = _service.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("nobody");

        Assert.IsEmpty(orders);
    }

    [TestMethod]
    [DataRow(1, 10, 10)]
    [DataRow(3, 5, 15)]
    [DataRow(1, 99.99, 99.99)]
    public void CreateOrder_SingleItem_TotalEqualsPrice(int qty, double price, double expectedTotal)
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = (decimal)price, Quantity = qty },
        };

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }
}
```

**Key patterns used:**

- **`sealed` test class** — better performance, signals no inheritance needed
- **`Assert.ThrowsExactly<T>`** — matches only the exact exception type (not subclasses)
- **Constructor initialization** — enables `readonly` fields
- **`Assert.HasCount`/`Assert.IsEmpty`/`Assert.AreSame`** — specific assertions with better failure messages
- **`[DataRow]`** — parameterized test for multiple inputs
- **AAA pattern** — clear Arrange/Act/Assert structure
